1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = {
13	  type: string;
14	  material?: string;
15	  enchantment?: number;
16	  cursed?: boolean;
17	};
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Damage = { itemType: string; amount: number };
20	type ClaimStep = {
21	  op: "claim";
22	  policy: number;
23	  incident: { cause: string; damages: Damage[] };
24	};
25	type Step = QuoteStep | ClaimStep;
26	type Customer = { yearsWithMHPCO: number };
27	type Scenario = { customer: Customer; steps: Step[] };
28	
29	const BLOCK_SIZE = 3;
30	const BLOCK_PREMIUM = 60;
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	
33	const CURSED_RATE = 0.5;
34	const HIGH_ENCHANTMENT_THRESHOLD = 5;
35	const HIGH_ENCHANTMENT_RATE = 0.3;
36	
37	type Rule<T> = { applies: (subject: T) => boolean; rate: number };
38	
39	const sumApplicableRates = <T>(rules: Rule<T>[], subject: T): number =>
40	  rules
41	    .filter((rule) => rule.applies(subject))
42	    .reduce((sum, rule) => sum + rule.rate, 0);
43	
44	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
45	
46	const isCursed = (item: Item): boolean => item.cursed === true;
47	const isHighlyEnchanted = (item: Item): boolean =>
48	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
49	
50	const SURCHARGE_RULES: Rule<Item>[] = [
51	  { applies: isCursed, rate: CURSED_RATE },
52	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
53	];
54	
55	const groupByType = (items: Item[]): Map<string, Item[]> => {
56	  const groups = new Map<string, Item[]>();
57	  for (const item of items) {
58	    const group = groups.get(item.type) ?? [];
59	    group.push(item);
60	    groups.set(item.type, group);
61	  }
62	  return groups;
63	};
64	
65	const basePremiumFor = (type: string) => {
66	  const base = BASE_PREMIUM[type];
67	  if (base === undefined) throw new Error(`Unknown item type: ${type}`);
68	  return base;
69	};
70	
71	const premiumForGroup = (type: string, group: Item[]) => {
72	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
73	    return BLOCK_PREMIUM;
74	  }
75	  return group.length * basePremiumFor(type);
76	};
77	
78	const surchargeForItem = (item: Item) =>
79	  basePremiumFor(item.type) * sumApplicableRates(SURCHARGE_RULES, item);
80	
81	const policyBasePremium = (items: Item[]) =>
82	  [...groupByType(items)].reduce(
83	    (total, [type, group]) => total + premiumForGroup(type, group),
84	    0,
85	  );
86	
87	const totalItemSurcharges = (items: Item[]) =>
88	  items.reduce((sum, item) => sum + surchargeForItem(item), 0);
89	
90	const FIRST_INSURANCE_RATE = 0.1;
91	const LOYALTY_THRESHOLD_YEARS = 2;
92	const LOYALTY_RATE = 0.2;
93	const FOLLOWUP_RATE = 0.15;
94	
95	type QuoteContext = { customer: Customer; stepIndex: number };
96	
97	const POLICY_ADJUSTMENTS: Rule<QuoteContext>[] = [
98	  { applies: () => true, rate: FIRST_INSURANCE_RATE },
99	  {
100	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
101	    rate: -LOYALTY_RATE,
102	  },
103	  { applies: ({ stepIndex }) => stepIndex > 0, rate: -FOLLOWUP_RATE },
104	];
105	
106	const policyAdjustment = (ctx: QuoteContext, policyBase: number) =>
107	  policyBase * sumApplicableRates(POLICY_ADJUSTMENTS, ctx);
108	
109	const quote = (step: QuoteStep, customer: Customer, stepIndex: number) => {
110	  const { items } = step;
111	  const policyBase = policyBasePremium(items);
112	  const premium =
113	    policyBase +
114	    policyAdjustment({ customer, stepIndex }, policyBase) +
115	    totalItemSurcharges(items);
116	  return { premium: Math.ceil(premium) + PROCESSING_FEE };
117	};
118	
119	const INSURANCE_VALUE_MULTIPLIER = 10;
120	const DEDUCTIBLE = 100;
121	const CAP_MULTIPLIER = 2;
122	
123	const insuranceValueFor = (type: string) =>
124	  basePremiumFor(type) * INSURANCE_VALUE_MULTIPLIER;
125	
126	const insuranceSum = (items: Item[]) =>
127	  items.reduce((sum, item) => sum + insuranceValueFor(item.type), 0);
128	
129	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
130	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
131	
132	const reimbursableDamage = (item: Item, damage: Damage) =>
133	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
134	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
135	    : damage.amount;
136	
137	const payoutForDamage = (item: Item, damage: Damage) =>
138	  Math.max(0, reimbursableDamage(item, damage) - DEDUCTIBLE);
139	
140	type PolicyState = { items: Item[]; remainingCap: number };
141	
142	const itemForDamage = (items: Item[], damage: Damage): Item => {
143	  const item = items.find((i) => i.type === damage.itemType);
144	  if (!item) throw new Error(`No insured ${damage.itemType} in policy`);
145	  return item;
146	};
147	
148	const totalPayout = (items: Item[], damages: Damage[]) =>
149	  damages.reduce(
150	    (sum, d) => sum + payoutForDamage(itemForDamage(items, d), d),
151	    0,
152	  );
153	
154	const newPolicy = (items: Item[]): PolicyState => ({
155	  items,
156	  remainingCap: insuranceSum(items) * CAP_MULTIPLIER,
157	});
158	
159	const claim = (step: ClaimStep, policies: PolicyState[]) => {
160	  const policy = policies[step.policy];
161	  const payout = totalPayout(policy.items, step.incident.damages);
162	  policy.remainingCap -= payout;
163	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
164	};
165	
166	export const run = (input: Scenario): unknown => {
167	  const policies: PolicyState[] = [];
168	  const results = input.steps.map((step, i) => {
169	    if (step.op === "quote") {
170	      policies[i] = newPolicy(step.items);
171	      return quote(step, input.customer, i);
172	    }
173	    return claim(step, policies);
174	  });
175	  return { results };
176	};
